update re_demand_job_describes set
update_time = getdate()



    ,job_name = #{jobName,jdbcType=VARCHAR}




    ,dept_name = #{deptName,jdbcType=VARCHAR}




    ,directly_under = #{directlyUnder,jdbcType=VARCHAR}




    ,job_describes = #{jobDescribes,jdbcType=VARCHAR}




    ,job_content = #{jobContent,jdbcType=VARCHAR}




    ,work_qualification = #{workQualification,jdbcType=VARCHAR}




    ,check_flag = #{checkFlag,jdbcType=BIT}




    ,enabled_flag = #{enabledFlag,jdbcType=BIT}




    ,dept_id = #{deptId,jdbcType=BIGINT}




    ,education = #{education,jdbcType=VARCHAR}




    ,sex = #{sex,jdbcType=VARCHAR}




    ,age = #{age,jdbcType=VARCHAR}




    ,work_age = #{workAge,jdbcType=VARCHAR}




    ,work_experence_age = #{workExperenceAge,jdbcType=VARCHAR}




    ,necessary_certificates = #{necessaryCertificates,jdbcType=VARCHAR}




    ,other_skills_requirements = #{otherSkillsRequirements,jdbcType=VARCHAR}




    ,skills_requirements = #{skillsRequirements,jdbcType=VARCHAR}



     where id = #{id,jdbcType=BIGINT}
